    fork
      // AW
      forever begin
        automatic ax_beat_t ax;
        this.drv.mon_aw(ax);
        aw_mbx.put(ax);
      end
      // W
      forever begin
        automatic w_beat_t w;
        this.drv.mon_w(w);
        w_mbx.put(w);
      end
      // B
      forever begin
        automatic b_beat_t b;
        this.drv.mon_b(b);
        b_mbx.put(b);
      end
      // AR
      forever begin
        automatic ax_beat_t ax;
        this.drv.mon_ar(ax);
        ar_mbx.put(ax);
      end
      // R
      forever begin
        automatic r_beat_t r;
        this.drv.mon_r(r);
        r_mbx.put(r);
      end
    join
  endtask
endclass

